  ('impulse', 'gt', 154, 'GT', '冲动；推动力；一时的念头', 'a sudden desire to act or a force that starts movement', 'She had an impulse to open the old box.', '她一时冲动想打开那个旧盒子。', '[{"w":"idea","def":"idea: 相关的一般事物或抽象概念","vs":"与 impulse 相比，和主词同属通用名词，但关注点不同","use":"讨论事实、关系、状态或日常事件，例如 \"idea\" / \"impulse\" 的替换练习"},{"w":"increase","def":"increase: 可与主词一起记忆的概念词","vs":"与 impulse 相比，比主词更偏向原因、结果、过程或对象","use":"阅读理解、概念分类、写作替换，例如 \"increase\" / \"impulse\" 的替换练习"},{"w":"industry","def":"industry: 同类通用名词","vs":"与 impulse 相比，语义相近但适用的语境边界不同","use":"主题词汇组、段落表达，例如 \"industry\" / \"impulse\" 的替换练习"}]'),
  ('increase', 'gt', 155, 'GT', '增加；增长；增量', 'a rise in number, size, or amount', 'There was an increase in trade after the road opened.', '道路开通后，贸易有所增加。', '[{"w":"impulse","def":"impulse: 相关的一般事物或抽象概念","vs":"与 increase 相比，和主词同属通用名词，但关注点不同","use":"讨论事实、关系、状态或日常事件，例如 \"impulse\" / \"increase\" 的替换练习"},{"w":"industry","def":"industry: 可与主词一起记忆的概念词","vs":"与 increase 相比，比主词更偏向原因、结果、过程或对象","use":"阅读理解、概念分类、写作替换，例如 \"industry\" / \"increase\" 的替换练习"},{"w":"ink","def":"ink: 同类通用名词","vs":"与 increase 相比，语义相近但适用的语境边界不同","use":"主题词汇组、段落表达，例如 \"ink\" / \"increase\" 的替换练习"}]');
